	},
}

// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter allows customization of where the user should be redirected after auth.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Generate cryptographically secure random state
	state, err := generateRandomState(32)
	if err != nil {
		return "", fmt.Errorf("failed to generate state: %w", err)
	}

	// Validate redirectPath against trusted domain
	redirectURL, err := validateRedirectURL(redirectPath)
	if err != nil {
		return "", fmt.Errorf("invalid redirect URL: %w", err)
	}

	// Create config copy with validated redirect URL
	config := *OAuthConfig
	config.RedirectURL = redirectURL

	// Generate authorization URL with state
	authURL := config.AuthCodeURL(state, oauth2.AccessTypeOffline)

	// Set state cookie with security attributes
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteStrictMode,
		Path:     "/",
		MaxAge:   300, // 5 minutes expiration
	})

	return authURL, nil
}

// generateRandomState creates URL-safe random state token
func generateRandomState(length int) (string, error) {
	b := make([]byte, length)
	if _, err := rand.Read(b); err != nil {
		return "", err
	}
	return base64.URLEncoding.EncodeToString(b), nil
}

// validateRedirectURL ensures URL is safe for redirection
func validateRedirectURL(redirectPath string) (string, error) {
	if redirectPath == "" {
		return OAuthConfig.RedirectURL, nil
	}

	// Parse base domain from configured redirect URL
	baseURL, err := url.Parse(OAuthConfig.RedirectURL)
	if err != nil {
		return "", fmt.Errorf("invalid base redirect URL: %w", err)
	}

	// Handle relative paths
	if strings.HasPrefix(redirectPath, "/") {
		return baseURL.Scheme + "://" + baseURL.Host + redirectPath, nil
	}

	// Validate absolute URLs
	parsedURL, err := url.Parse(redirectPath)
	if err != nil {
		return "", fmt.Errorf("malformed URL: %w", err)
	}

	// Ensure same host and scheme
	if parsedURL.Host != baseURL.Host || parsedURL.Scheme != baseURL.Scheme {
		return "", fmt.Errorf("domain mismatch: must use %s", baseURL.Host)
	}

	return redirectPath, nil
}

